import{_ as a,o as i,c as t,ag as e}from"./chunks/framework.C9sp7nFj.js";const o=JSON.parse('{"title":"从 React 17 开始在 JSX 文件中不需要手动import React","description":"","frontmatter":{},"headers":[],"relativePath":"react/other/1.md","filePath":"react/other/1.md"}'),l={name:"react/other/1.md"};function h(n,s,p,k,r,c){return i(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="从-react-17-开始在-jsx-文件中不需要手动import-react" tabindex="-1">从 React 17 开始在 JSX 文件中不需要手动import React <a class="header-anchor" href="#从-react-17-开始在-jsx-文件中不需要手动import-react" aria-label="Permalink to &quot;从 React 17 开始在 JSX 文件中不需要手动import React&quot;">​</a></h1><h2 id="_1-历史原因-早期版本需要手动导入" tabindex="-1">1. 历史原因（早期版本需要手动导入） <a class="header-anchor" href="#_1-历史原因-早期版本需要手动导入" aria-label="Permalink to &quot;1. 历史原因（早期版本需要手动导入）&quot;">​</a></h2><p>在 React 早期，JSX 会被 Babel 等工具转译为纯 JavaScript 代码。例如，下面的 JSX 代码</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> element</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">div</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Hello, React!&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">div</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;;</span></span></code></pre></div><p>会被转译为类似这样的 JavaScript 代码：</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> element</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> React.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">createElement</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;div&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">null</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Hello, React!&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>这里React.createElement用于创建 React 元素，所以在早期必须手动导入 React，才能在代码中使用React对象调用createElement方法。</p><h2 id="_2-自动导入-react-的原理" tabindex="-1">2. 自动导入 React 的原理 <a class="header-anchor" href="#_2-自动导入-react-的原理" aria-label="Permalink to &quot;2. 自动导入 React 的原理&quot;">​</a></h2><p>从 React 17 开始，引入了新的 JSX 转换机制。Babel 不再将 JSX 转换为React.createElement，而是使用了新的入口函数jsx和jsxDEV（用于开发环境）。这些函数位于react/jsx - runtime和react/jsx - dev - runtime模块中。</p><p>例如，上述同样的 JSX 代码，在新机制下转译后的 JavaScript 代码大致如下：</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { jsx </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> _jsx } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;react/jsx - runtime&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> element</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> _jsx</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;div&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, { children: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Hello, React!&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> });</span></span></code></pre></div><p>这里jsx函数负责创建 React 元素。由于 Babel 自动导入了react/jsx - runtime模块中的jsx函数，开发者无需再手动导入React。</p><h2 id="_3-对开发者的影响" tabindex="-1">3. 对开发者的影响 <a class="header-anchor" href="#_3-对开发者的影响" aria-label="Permalink to &quot;3. 对开发者的影响&quot;">​</a></h2><ul><li>简化代码：开发者无需再在每个包含 JSX 的文件顶部添加import React from&#39;react&#39;;语句，使代码更加简洁，尤其是在一个项目中有大量的 JSX 文件时，这种简化效果更为明显。</li><li>兼容性注意：如果项目仍在使用旧版本的 React，或者使用的工具链不支持新的 JSX 转换机制，依然需要手动导入 React。例如，在 React 16 及更早版本中，手动导入 React 是必不可少的。</li></ul>`,14)])])}const E=a(l,[["render",h]]);export{o as __pageData,E as default};
